import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import DAODevelopmentScreen from "@screens/dao-development/";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const DAODevelopmentPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "DAO Development Company", link: null },
  ];
  const { data } = props;
  const fileUrl =
    data?.daoDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "DAO development company delivering secure, scalable decentralized governance solutions with smart contracts and token voting.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1601",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is DAO development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "DAO development is building decentralized organizations using blockchain and smart contracts for transparent, automated governance.",
            },
          },
          {
            "@type": "Question",
            name: "How to choose a blockchain network for DAO deployment?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "To choose a blockchain network for DAO deployment, consider factors like transaction fees, scalability, security, community support, and compatibility with smart contracts and governance tools.",
            },
          },
          {
            "@type": "Question",
            name: "What is the work of DAO?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The work of a DAO (Decentralized Autonomous Organization) is to manage decisions, funds, and operations transparently using smart contracts and community voting without a central authority.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <DAODevelopmentScreen db={db} />
      </main>
    </Layout_v2>
  );
};

export default DAODevelopmentPage;

export const queryData = graphql`
  query MyQuery {
    daoDevImg: file(relativePath: { eq: "dao-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "dao-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
